def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = 1 / j
            term = ratio ** j
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += weight * term
        if capacity < item * 1.5:
            score *= 2
            for k in range(1, 4):
                score += (item / (capacity + k)) * 0.1 * k
        elif capacity > item * 4:
            score *= 0.5
            for k in range(1, 3):
                if (capacity / k) > item:
                    score -= 0.05 * k
                else:
                    score += 0.02 * k
        else:
            for m in range(1, 5):
                if (capacity % m) == 0:
                    score += 0.03 * m
                else:
                    score -= 0.01 * m
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
